import path from 'path'
import { createRequire } from 'module'
import { fileURLToPath } from 'url'

const require = createRequire(import.meta.url)

export function getBaseViteConfig() {
    const phaserPath = path.dirname(require.resolve('phaser/package.json'))
    const makiPath = fileURLToPath(new URL('../index.js', import.meta.url))

    return {
        root: process.cwd(),
        publicDir: path.join(process.cwd(), 'assets'),
        resolve: {
            alias: {
                phaser: phaserPath,
                '@tialops/maki': makiPath,
                maki: makiPath,
            }
        }
    }
}